import type { PrismaClient } from '../../generated/prisma/client.js';

export async function seedLiar(prisma: PrismaClient, catMap: Record<string, string>) {
  await prisma.quiz.upsert({
    where: { slug: 'liar' },
    update: {
      title: { es: '¿Qué tipo de mentiroso/a eres?', en: 'What type of liar are you?', fr: 'Quel type de menteur/menteuse êtes-vous ?', de: 'Was für ein Lügner bist du?', it: 'Che tipo di bugiardo/a sei?', pt: 'Que tipo de mentiroso/a você é?' },
      description: { es: 'Todos mentimos. La pregunta es: ¿por qué lo haces, con qué frecuencia y qué tan bien te va?', en: 'Everyone lies. The question is: why do you do it, how often, and how well does it serve you?', fr: 'Tout le monde ment. La question est : pourquoi le fais-tu, à quelle fréquence et dans quelle mesure ça te réussit ?', de: 'Alle lügen. Die Frage ist: Warum tust du es, wie oft und wie gut geht es dir dabei?', it: 'Tutti mentono. La domanda è: perché lo fai, con quale frequenza e quanto ti riesce bene?', pt: 'Todo mundo mente. A questão é: por que você faz isso, com que frequência e o quão bem isso funciona para você?' },
      scenarioLabel: { es: 'Situación', en: 'Situation', fr: 'Situation', de: 'Situation', it: 'Situazione', pt: 'Situação' },
      dimensionLabels: {
        es: { B: 'Benevolencia', A: 'Autoprotección', S: 'Social', H: 'Honestidad' },
        en: { B: 'Benevolence', A: 'Self-protection', S: 'Social', H: 'Honesty' },
        fr: { B: 'Bienveillance', A: 'Auto-protection', S: 'Social', H: 'Honnêteté' },
        de: { B: 'Wohlwollen', A: 'Selbstschutz', S: 'Sozial', H: 'Ehrlichkeit' },
        it: { B: 'Benevolenza', A: 'Autoprotezzione', S: 'Sociale', H: 'Onestà' },
        pt: { B: 'Benevolência', A: 'Autoproteção', S: 'Social', H: 'Honestidade' },
      },
      questions: [
        { id: 1, situation: { es: 'Tu mejor amigo estrena una nueva canción que compuso. Es terrible. Te pregunta qué te parece.', en: 'Your best friend releases a new song they wrote. It\'s terrible. They ask what you think.', fr: 'Ton meilleur ami sort une nouvelle chanson qu\'il a composée. Elle est terrible. Il te demande ce que tu en penses.', de: 'Dein bester Freund veröffentlicht ein neues Lied, das er komponiert hat. Es ist schrecklich. Er fragt dich, was du davon hältst.', it: 'Il tuo migliore amico pubblica una nuova canzone che ha composto. È terribile. Ti chiede cosa ne pensi.', pt: 'Seu melhor amigo lança uma nova música que compôs. É horrível. Ele te pergunta o que você acha.' }, options: [{ text: { es: 'Le digo que es increíble. No voy a destruir su ilusión.', en: 'I tell them it\'s incredible. I\'m not going to crush their dream.', fr: 'Je lui dis que c\'est incroyable. Je ne vais pas briser son illusion.', de: 'Ich sage ihm, dass es großartig ist. Ich werde seine Illusion nicht zerstören.', it: 'Gli dico che è incredibile. Non voglio distruggere la sua illusione.', pt: 'Digo que é incrível. Não vou destruir a ilusão dele.' }, dimension: 'B' }, { text: { es: 'Le digo que está buena para no tener que justificar por qué no me gusta.', en: 'I say it\'s good so I don\'t have to explain why I don\'t like it.', fr: 'Je dis qu\'elle est bien pour ne pas avoir à expliquer pourquoi elle ne me plaît pas.', de: 'Ich sage, es ist gut, damit ich nicht erklären muss, warum es mir nicht gefällt.', it: 'Dico che è buona per non dover spiegare perché non mi piace.', pt: 'Digo que está boa para não ter que justificar por que não gostei.' }, dimension: 'A' }, { text: { es: 'Digo algo vago como "tiene mucha energía" y cambio el tema.', en: 'I say something vague like "it has a lot of energy" and change the subject.', fr: 'Je dis quelque chose de vague comme "elle a beaucoup d\'énergie" et je change de sujet.', de: 'Ich sage etwas Vages wie "es hat viel Energie" und wechsle das Thema.', it: 'Dico qualcosa di vago come "ha molta energia" e cambio argomento.', pt: 'Digo algo vago como "tem muita energia" e mudo de assunto.' }, dimension: 'S' }, { text: { es: 'Le digo que no es para mí pero que celebro que haya hecho algo propio.', en: 'I tell them it\'s not my thing but I celebrate that they created something of their own.', fr: 'Je lui dis que ce n\'est pas pour moi, mais que je salue le fait qu\'il ait créé quelque chose qui lui appartient.', de: 'Ich sage ihm, dass es nicht meins ist, aber ich feiere, dass er etwas Eigenes geschaffen hat.', it: 'Gli dico che non fa per me, ma apprezzo che abbia creato qualcosa di suo.', pt: 'Digo que não é para mim, mas celebro o fato de ter criado algo próprio.' }, dimension: 'H' }] },
        { id: 2, situation: { es: 'Llegas tarde a una reunión importante. ¿Qué dices?', en: 'You arrive late to an important meeting. What do you say?', fr: 'Tu arrives en retard à une réunion importante. Qu\'est-ce que tu dis ?', de: 'Du kommst zu einem wichtigen Meeting zu spät. Was sagst du?', it: 'Arrivi in ritardo a una riunione importante. Cosa dici?', pt: 'Você chega atrasado a uma reunião importante. O que você diz?' }, options: [{ text: { es: 'Invento algo: tráfico, emergencia, lo que suene creíble.', en: 'I make something up: traffic, an emergency, whatever sounds believable.', fr: 'J\'invente quelque chose : la circulation, une urgence, ce qui paraît crédible.', de: 'Ich erfinde etwas: Verkehr, Notfall, was auch immer glaubwürdig klingt.', it: 'Invento qualcosa: traffico, emergenza, qualcosa di credibile.', pt: 'Invento algo: trânsito, emergência, o que soar mais crível.' }, dimension: 'A' }, { text: { es: 'Digo que hubo un problema sin especificar. No es una mentira, exactamente.', en: 'I say there was a problem without specifying. It\'s not exactly a lie.', fr: 'Je dis qu\'il y a eu un problème sans préciser. Ce n\'est pas vraiment un mensonge.', de: 'Ich sage, es gab ein Problem, ohne Einzelheiten zu nennen. Das ist nicht direkt eine Lüge.', it: 'Dico che c\'è stato un problema senza specificare. Non è esattamente una bugia.', pt: 'Digo que houve um problema sem especificar. Não é exatamente uma mentira.' }, dimension: 'S' }, { text: { es: 'Pido disculpas sin dar explicaciones. La verdad no cambia nada.', en: 'I apologize without giving explanations. The truth doesn\'t change anything.', fr: 'Je m\'excuse sans donner d\'explication. La vérité ne changerait rien.', de: 'Ich entschuldige mich ohne Erklärungen. Die Wahrheit ändert nichts.', it: 'Chiedo scusa senza spiegazioni. La verità non cambia nulla.', pt: 'Peço desculpas sem dar explicações. A verdade não muda nada.' }, dimension: 'H' }, { text: { es: 'Invento algo que no haga quedar mal a nadie involucrado.', en: 'I make up something that doesn\'t make anyone involved look bad.', fr: 'J\'invente quelque chose qui ne fasse pas paraître quelqu\'un de mal.', de: 'Ich erfinde etwas, das niemanden schlecht aussehen lässt.', it: 'Invento qualcosa che non metta in cattiva luce nessuno.', pt: 'Invento algo que não prejudique ninguém envolvido.' }, dimension: 'B' }] },
        { id: 3, situation: { es: 'Tu pareja pregunta si esa persona que te escribió es alguien importante. No lo es, pero fue flirteo.', en: 'Your partner asks if the person who texted you is someone important. They\'re not, but there was flirting.', fr: 'Ton/ta partenaire te demande si la personne qui t\'a écrit est quelqu\'un d\'important. Non, mais c\'était du flirt.', de: 'Dein Partner fragt, ob die Person, die dir geschrieben hat, jemand Wichtiges ist. Nein, aber es war Flirten.', it: 'Il/la tuo/a partner ti chiede se quella persona che ti ha scritto è qualcuno di importante. Non lo è, ma c\'era del flirt.', pt: 'Seu parceiro pergunta se a pessoa que te escreveu é alguém importante. Não é, mas havia flerte.' }, options: [{ text: { es: 'Digo que es un conocido del trabajo. Técnicamente no es mentira.', en: 'I say it\'s a work acquaintance. Technically not a lie.', fr: 'Je dis que c\'est une connaissance du travail. Techniquement, ce n\'est pas un mensonge.', de: 'Ich sage, es ist ein Arbeitskollege. Technisch gesehen keine Lüge.', it: 'Dico che è un conoscente del lavoro. Tecnicamente non è una bugia.', pt: 'Digo que é um conhecido do trabalho. Tecnicamente não é mentira.' }, dimension: 'S' }, { text: { es: 'Lo niego directamente. No pasó nada importante y no vale la pena el conflicto.', en: 'I deny it directly. Nothing important happened and the conflict isn\'t worth it.', fr: 'Je nie directement. Il ne s\'est rien passé d\'important et ça ne vaut pas le conflit.', de: 'Ich leugne es direkt. Es ist nichts Wichtiges passiert und der Konflikt lohnt sich nicht.', it: 'Lo nego direttamente. Non è successo niente di importante e non vale il conflitto.', pt: 'Nego diretamente. Não aconteceu nada importante e não vale o conflito.' }, dimension: 'A' }, { text: { es: 'Cuento todo. Fue sin importancia, pero prefiero no cargar con el secreto.', en: 'I tell everything. It meant nothing, but I prefer not to carry the secret.', fr: 'Je raconte tout. Ce n\'était rien, mais je préfère ne pas porter ce secret.', de: 'Ich erzähle alles. Es war nichts, aber ich trage das Geheimnis lieber nicht.', it: 'Racconto tutto. Non era niente, ma preferisco non portare il segreto.', pt: 'Conto tudo. Não teve importância, mas prefiro não carregar o segredo.' }, dimension: 'H' }, { text: { es: 'Minimizo para proteger sus sentimientos: "alguien del gym, nada relevante".', en: 'I minimize to protect their feelings: "someone from the gym, nothing relevant".', fr: 'Je minimise pour protéger ses sentiments : "quelqu\'un du gym, rien d\'important".', de: 'Ich spiele es herunter, um seine Gefühle zu schützen: "jemand aus dem Fitnessstudio, nichts Wichtiges".', it: 'Minimalizzo per proteggere i suoi sentimenti: "qualcuno della palestra, niente di rilevante".', pt: 'Minimizo para proteger seus sentimentos: "alguém da academia, nada relevante".' }, dimension: 'B' }] },
        { id: 4, situation: { es: 'Un familiar pide dinero que sabes que no va a devolver. No quieres prestarlo.', en: 'A family member asks for money you know they won\'t pay back. You don\'t want to lend it.', fr: 'Un membre de ta famille demande de l\'argent que tu sais qu\'il ne rendra pas. Tu ne veux pas le prêter.', de: 'Ein Familienmitglied bittet um Geld, von dem du weißt, dass es nicht zurückgezahlt wird. Du willst es nicht leihen.', it: 'Un familiare chiede soldi che sai che non restituirà. Non vuoi prestarli.', pt: 'Um familiar pede dinheiro que você sabe que não vai devolver. Você não quer emprestar.' }, options: [{ text: { es: 'Digo que en este momento no tengo. Es más fácil que dar una negativa real.', en: 'I say I don\'t have any right now. It\'s easier than a real refusal.', fr: 'Je dis que je n\'ai pas d\'argent en ce moment. C\'est plus facile qu\'un vrai refus.', de: 'Ich sage, ich habe gerade nichts. Es ist einfacher als eine echte Absage.', it: 'Dico che al momento non ho soldi. È più facile che un rifiuto diretto.', pt: 'Digo que no momento não tenho. É mais fácil do que uma negativa real.' }, dimension: 'A' }, { text: { es: 'Digo que lo pensaré y después no respondo más los mensajes.', en: 'I say I\'ll think about it and then stop responding to messages.', fr: 'Je dis que j\'y réfléchirai, puis je ne réponds plus aux messages.', de: 'Ich sage, ich werde darüber nachdenken, und antworte dann nicht mehr auf Nachrichten.', it: 'Dico che ci penserò e poi smetto di rispondere ai messaggi.', pt: 'Digo que vou pensar e depois paro de responder as mensagens.' }, dimension: 'S' }, { text: { es: 'Le digo que no lo voy a prestar porque sé que no me lo devolverá.', en: 'I tell them I won\'t lend it because I know they won\'t pay me back.', fr: 'Je lui dis que je ne vais pas prêter parce que je sais qu\'il ne me le rendra pas.', de: 'Ich sage ihm, dass ich es nicht leihe, weil ich weiß, dass er es nicht zurückzahlt.', it: 'Gli dico che non lo presterò perché so che non me lo restituirà.', pt: 'Digo que não vou emprestar porque sei que não vai me devolver.' }, dimension: 'H' }, { text: { es: 'Le digo que tengo mis propias deudas para no hacerlo sentir rechazado.', en: 'I tell them I have my own debts so they don\'t feel rejected.', fr: 'Je lui dis que j\'ai mes propres dettes pour ne pas lui faire sentir qu\'il est rejeté.', de: 'Ich sage ihm, dass ich eigene Schulden habe, damit er sich nicht abgelehnt fühlt.', it: 'Gli dico che ho i miei debiti per non farlo sentire rifiutato.', pt: 'Digo que tenho minhas próprias dívidas para não fazê-lo sentir rejeitado.' }, dimension: 'B' }] },
        { id: 5, situation: { es: 'Te preguntan si viste la película nueva que está de moda. No la viste y no te interesa.', en: 'Someone asks if you\'ve seen the new trendy movie. You haven\'t and you\'re not interested.', fr: 'On te demande si tu as vu le nouveau film à la mode. Tu ne l\'as pas vu et ça ne t\'intéresse pas.', de: 'Man fragt dich, ob du den neuen Trendfilm gesehen hast. Du hast ihn nicht gesehen und interessierst dich nicht dafür.', it: 'Ti chiedono se hai visto il nuovo film di tendenza. Non l\'hai visto e non ti interessa.', pt: 'Te perguntam se você viu o novo filme da moda. Você não viu e não tem interesse.' }, options: [{ text: { es: 'Digo que sí y comento algo genérico que encontré en reseñas.', en: 'I say yes and comment something generic I found in reviews.', fr: 'Je dis oui et je commente quelque chose de générique trouvé dans les critiques.', de: 'Ich sage ja und kommentiere etwas Allgemeines aus Rezensionen.', it: 'Dico di sì e commento qualcosa di generico trovato nelle recensioni.', pt: 'Digo que sim e comento algo genérico que encontrei nas críticas.' }, dimension: 'S' }, { text: { es: 'Digo que la tengo pendiente para no admitir que no me interesa nada.', en: 'I say it\'s on my list to avoid admitting I\'m not interested at all.', fr: 'Je dis qu\'elle est sur ma liste pour ne pas admettre qu\'elle ne m\'intéresse pas du tout.', de: 'Ich sage, sie steht auf meiner Liste, um nicht zuzugeben, dass sie mich gar nicht interessiert.', it: 'Dico che è nella mia lista per non ammettere che non mi interessa per niente.', pt: 'Digo que está na minha lista para não admitir que não me interessa nada.' }, dimension: 'A' }, { text: { es: 'Digo que no la vi y que no me llama la atención.', en: 'I say I haven\'t seen it and it doesn\'t appeal to me.', fr: 'Je dis que je ne l\'ai pas vue et qu\'elle ne m\'attire pas.', de: 'Ich sage, ich habe ihn nicht gesehen und er spricht mich nicht an.', it: 'Dico che non l\'ho visto e non mi attira.', pt: 'Digo que não vi e que não me chama a atenção.' }, dimension: 'H' }, { text: { es: 'Digo que la tenía pendiente pero que parece que no es para mí. Para no decepcionar.', en: 'I say it was on my list but it seems it\'s not for me. So as not to disappoint.', fr: 'Je dis qu\'elle était sur ma liste mais qu\'elle ne semble pas faite pour moi. Pour ne pas décevoir.', de: 'Ich sage, sie stand auf meiner Liste, scheint aber nichts für mich zu sein. Um nicht zu enttäuschen.', it: 'Dico che era nella mia lista ma che sembra non faccia per me. Per non deludere.', pt: 'Digo que estava na minha lista, mas que parece não ser para mim. Para não decepcionar.' }, dimension: 'B' }] },
        { id: 6, situation: { es: 'Tu jefe pregunta si terminaste un proyecto que en realidad tiene otro día de trabajo pendiente.', en: 'Your boss asks if you finished a project that actually has another day of work left.', fr: 'Ton patron te demande si tu as terminé un projet qui a en réalité encore une journée de travail devant lui.', de: 'Dein Chef fragt, ob du ein Projekt abgeschlossen hast, das eigentlich noch einen weiteren Arbeitstag braucht.', it: 'Il tuo capo ti chiede se hai terminato un progetto che in realtà ha ancora un giorno di lavoro da fare.', pt: 'Seu chefe pergunta se você terminou um projeto que na verdade ainda tem um dia de trabalho pendente.' }, options: [{ text: { es: 'Digo que está casi listo y trabajo toda la noche para que así sea.', en: 'I say it\'s almost done and work through the night to make it so.', fr: 'Je dis qu\'il est presque prêt et je travaille toute la nuit pour que ça le soit.', de: 'Ich sage, es ist fast fertig, und arbeite die ganze Nacht daran.', it: 'Dico che è quasi pronto e lavoro tutta la notte per farlo diventare così.', pt: 'Digo que está quase pronto e trabalho a noite toda para que seja assim.' }, dimension: 'A' }, { text: { es: 'Digo que sí y confío en terminarlo antes de que lo revise.', en: 'I say yes and trust I\'ll finish it before they review it.', fr: 'Je dis oui et je fais confiance à ma capacité de terminer avant qu\'il le vérifie.', de: 'Ich sage ja und vertraue darauf, es fertig zu stellen, bevor er es prüft.', it: 'Dico di sì e confido di finirlo prima che lo revisioni.', pt: 'Digo que sim e confio em terminá-lo antes que ele o revise.' }, dimension: 'S' }, { text: { es: 'Le digo que me falta un día y propongo un nuevo plazo.', en: 'I tell them I need one more day and propose a new deadline.', fr: 'Je lui dis qu\'il me manque une journée et je propose un nouveau délai.', de: 'Ich sage ihm, dass mir ein Tag fehlt, und schlage eine neue Frist vor.', it: 'Gli dico che mi manca un giorno e propongo una nuova scadenza.', pt: 'Digo que falta um dia e proponho um novo prazo.' }, dimension: 'H' }, { text: { es: 'Digo que hay algunos ajustes finales para suavizar la realidad.', en: 'I say there are some final adjustments to soften the reality.', fr: 'Je dis qu\'il y a quelques ajustements finaux pour adoucir la réalité.', de: 'Ich sage, es gibt noch ein paar letzte Anpassungen, um die Realität zu mildern.', it: 'Dico che ci sono alcuni aggiustamenti finali per ammorbidire la realtà.', pt: 'Digo que há alguns ajustes finais para suavizar a realidade.' }, dimension: 'B' }] },
        { id: 7, situation: { es: 'Tu grupo de amigos quiere hacer un plan que no te apetece nada. Te preguntan si vas.', en: 'Your friend group wants to do something you have no interest in. They ask if you\'re going.', fr: 'Ton groupe d\'amis veut faire un plan qui ne te dit rien. Ils te demandent si tu viens.', de: 'Deine Freundesgruppe möchte etwas machen, das dich gar nicht anspricht. Sie fragen, ob du kommst.', it: 'Il tuo gruppo di amici vuole fare qualcosa che non ti va per niente. Ti chiedono se ci sei.', pt: 'Seu grupo de amigos quer fazer um programa que não te agrada nada. Te perguntam se você vai.' }, options: [{ text: { es: 'Invento un compromiso previo. Así no ofendo a nadie.', en: 'I make up a prior commitment. That way I don\'t offend anyone.', fr: 'J\'invente un engagement antérieur. Comme ça, je n\'offense personne.', de: 'Ich erfinde eine frühere Verpflichtung. So beleidigige ich niemanden.', it: 'Invento un impegno precedente. Così non offendo nessuno.', pt: 'Invento um compromisso anterior. Assim não ofendo ninguém.' }, dimension: 'B' }, { text: { es: 'Digo que "quizás" y luego cancelo a último momento con cualquier excusa.', en: 'I say "maybe" and then cancel at the last minute with any excuse.', fr: 'Je dis "peut-être" et j\'annule à la dernière minute avec n\'importe quelle excuse.', de: 'Ich sage "vielleicht" und sage dann in letzter Minute mit irgendeiner Ausrede ab.', it: 'Dico "forse" e poi cancello all\'ultimo momento con qualsiasi scusa.', pt: 'Digo que "talvez" e depois cancelo de última hora com qualquer desculpa.' }, dimension: 'A' }, { text: { es: 'Digo que lo veo complicado sin dar detalles.', en: 'I say it\'s complicated without giving details.', fr: 'Je dis que ça semble compliqué sans donner de détails.', de: 'Ich sage, es ist kompliziert, ohne Details zu nennen.', it: 'Dico che lo vedo complicato senza dare dettagli.', pt: 'Digo que vejo complicado sem dar detalhes.' }, dimension: 'S' }, { text: { es: 'Digo que no es para mí ese tipo de plan y propongo algo diferente.', en: 'I say that type of plan isn\'t for me and suggest something different.', fr: 'Je dis que ce type de plan n\'est pas pour moi et je propose quelque chose de différent.', de: 'Ich sage, diese Art von Plan ist nichts für mich, und schlage etwas anderes vor.', it: 'Dico che quel tipo di piano non fa per me e propongo qualcosa di diverso.', pt: 'Digo que esse tipo de programa não é para mim e proponho algo diferente.' }, dimension: 'H' }] },
        { id: 8, situation: { es: 'Rompes algo valioso de tu pareja por accidente. Nadie lo vio.', en: 'You accidentally break something valuable belonging to your partner. Nobody saw it.', fr: 'Tu casses accidentellement quelque chose de précieux appartenant à ton/ta partenaire. Personne ne l\'a vu.', de: 'Du zerbrichst versehentlich etwas Wertvolles von deinem Partner. Niemand hat es gesehen.', it: 'Rompi accidentalmente qualcosa di prezioso del tuo/a partner. Nessuno ha visto.', pt: 'Você quebra acidentalmente algo valioso do seu parceiro. Ninguém viu.' }, options: [{ text: { es: 'Lo escondo y cuando lo descubran, digo que no sé qué pasó.', en: 'I hide it and when they discover it, I say I don\'t know what happened.', fr: 'Je le cache et quand on le découvre, je dis que je ne sais pas ce qui s\'est passé.', de: 'Ich verstecke es, und wenn es entdeckt wird, sage ich, dass ich nicht weiß, was passiert ist.', it: 'Lo nascondo e quando lo scoprono, dico che non so cosa è successo.', pt: 'Escondo e quando descobrirem, digo que não sei o que aconteceu.' }, dimension: 'A' }, { text: { es: 'Digo que lo encontré así. Quizás ya estaba roto antes.', en: 'I say I found it like that. Maybe it was already broken.', fr: 'Je dis que je l\'ai trouvé comme ça. Peut-être qu\'il était déjà cassé avant.', de: 'Ich sage, ich habe es so gefunden. Vielleicht war es schon vorher kaputt.', it: 'Dico che l\'ho trovato così. Forse era già rotto prima.', pt: 'Digo que encontrei assim. Talvez já estivesse quebrado antes.' }, dimension: 'S' }, { text: { es: 'Lo cuento inmediatamente. Los accidentes pasan y ocultarlo sería peor.', en: 'I tell them immediately. Accidents happen and hiding it would be worse.', fr: 'Je le dis immédiatement. Les accidents arrivent et le cacher serait pire.', de: 'Ich sage es sofort. Unfälle passieren und es zu verbergen wäre schlimmer.', it: 'Lo dico immediatamente. Gli incidenti capitano e nasconderlo sarebbe peggio.', pt: 'Conto imediatamente. Acidentes acontecem e esconder seria pior.' }, dimension: 'H' }, { text: { es: 'Lo reemplazo en secreto antes de que se dé cuenta. Sin necesidad de conversaciones difíciles.', en: 'I replace it secretly before they notice. No need for difficult conversations.', fr: 'Je le remplace secrètement avant qu\'ils s\'en aperçoivent. Sans avoir besoin de conversations difficiles.', de: 'Ich ersetze es heimlich, bevor sie es bemerken. Ohne schwierige Gespräche.', it: 'Lo sostituisco in segreto prima che se ne accorga. Senza bisogno di conversazioni difficili.', pt: 'Substituo em segredo antes que perceba. Sem necessidade de conversas difíceis.' }, dimension: 'B' }] },
        { id: 9, situation: { es: 'Alguien te pregunta cuánto ganaste en tu último trabajo. Es una pregunta incómoda.', en: 'Someone asks how much you earned at your last job. It\'s an uncomfortable question.', fr: 'Quelqu\'un te demande combien tu gagnais dans ton dernier travail. C\'est une question inconfortable.', de: 'Jemand fragt dich, wie viel du in deinem letzten Job verdient hast. Eine unangenehme Frage.', it: 'Qualcuno ti chiede quanto guadagnavi nel tuo ultimo lavoro. È una domanda scomoda.', pt: 'Alguém te pergunta quanto você ganhou no seu último emprego. É uma pergunta desconfortável.' }, options: [{ text: { es: 'Doy una cifra 20% más alta. Es una negociación, no una confesión.', en: 'I give a number 20% higher. It\'s a negotiation, not a confession.', fr: 'Je donne un chiffre 20 % plus élevé. C\'est une négociation, pas une confession.', de: 'Ich nenne eine Zahl, die 20 % höher ist. Das ist eine Verhandlung, kein Geständnis.', it: 'Do una cifra del 20% più alta. È una trattativa, non una confessione.', pt: 'Dou um número 20% maior. É uma negociação, não uma confissão.' }, dimension: 'A' }, { text: { es: 'Doy una cifra aproximada que suene bien sin ser exacta.', en: 'I give an approximate number that sounds good without being exact.', fr: 'Je donne un chiffre approximatif qui sonne bien sans être exact.', de: 'Ich nenne eine ungefähre Zahl, die gut klingt, ohne genau zu sein.', it: 'Do una cifra approssimativa che suoni bene senza essere esatta.', pt: 'Dou um número aproximado que soe bem sem ser exato.' }, dimension: 'S' }, { text: { es: 'Digo la cifra real. No tengo nada que esconder.', en: 'I say the real number. I have nothing to hide.', fr: 'Je donne le vrai chiffre. Je n\'ai rien à cacher.', de: 'Ich sage die echte Zahl. Ich habe nichts zu verbergen.', it: 'Dico la cifra reale. Non ho nulla da nascondere.', pt: 'Digo o número real. Não tenho nada a esconder.' }, dimension: 'H' }, { text: { es: 'Evado la pregunta con un "depende del contexto" para no incomodar.', en: 'I dodge the question with a "it depends on context" so as not to make anyone uncomfortable.', fr: 'J\'esquive la question avec un "ça dépend du contexte" pour ne pas mettre mal à l\'aise.', de: 'Ich weiche der Frage mit einem "es kommt auf den Kontext an" aus, um niemanden in Verlegenheit zu bringen.', it: 'Evito la domanda con un "dipende dal contesto" per non mettere a disagio.', pt: 'Esquivo da pergunta com um "depende do contexto" para não constranger.' }, dimension: 'B' }] },
        { id: 10, situation: { es: 'Tu amigo/a te pregunta qué piensas de su nueva pareja. No te cae bien.', en: 'Your friend asks what you think of their new partner. You don\'t like them.', fr: 'Ton/ta ami(e) te demande ce que tu penses de son/sa nouveau/nouvelle partenaire. Tu ne l\'aimes pas.', de: 'Dein Freund/deine Freundin fragt dich, was du von seinem/ihrem neuen Partner hältst. Du magst ihn/sie nicht.', it: 'Il/la tuo/a amico/a ti chiede cosa pensi del/della suo/a nuovo/a partner. Non ti piace.', pt: 'Seu amigo/a te pergunta o que você acha do novo parceiro/a. Você não gosta.' }, options: [{ text: { es: 'Le digo que parece muy buena persona aunque no me haya parecido tal cosa.', en: 'I tell them they seem like a great person even though I don\'t think so.', fr: 'Je lui dis que ça a l\'air d\'être une très bonne personne même si ce n\'est pas mon avis.', de: 'Ich sage, er/sie wirkt wie eine tolle Person, obwohl ich das nicht finde.', it: 'Gli dico che sembra una persona molto buona anche se non la penso così.', pt: 'Digo que parece uma ótima pessoa mesmo não pensando isso.' }, dimension: 'B' }, { text: { es: 'Digo que es pronto para opinar y que lo que importa es que mi amigo/a sea feliz.', en: 'I say it\'s too early to give an opinion and that what matters is my friend\'s happiness.', fr: 'Je dis qu\'il est trop tôt pour donner mon avis et que ce qui compte c\'est que mon ami(e) soit heureux/heureuse.', de: 'Ich sage, es ist zu früh für eine Meinung und was zählt ist, dass mein Freund/meine Freundin glücklich ist.', it: 'Dico che è presto per esprimere un opinione e che ciò che conta è che il/la mio/a amico/a sia felice.', pt: 'Digo que é cedo para opinar e que o que importa é que meu/minha amigo/a seja feliz.' }, dimension: 'S' }, { text: { es: 'Guardo mis opiniones. No me lo preguntaron para que destruya algo que lo hace feliz.', en: 'I keep my opinions to myself. They didn\'t ask me to destroy something that makes them happy.', fr: 'Je garde mes opinions pour moi. On ne m\'a pas demandé de détruire quelque chose qui rend mon ami(e) heureux/heureuse.', de: 'Ich behalte meine Meinung für mich. Man hat mich nicht gefragt, um etwas zu zerstören, das ihn/sie glücklich macht.', it: 'Tengo le mie opinioni per me. Non mi è stato chiesto di distruggere qualcosa che lo rende felice.', pt: 'Guardo minhas opiniões. Não me pediram para destruir algo que o faz feliz.' }, dimension: 'A' }, { text: { es: 'Le digo que no me terminó de convencer pero que es mi opinión y que lo quiero igual.', en: 'I tell them I\'m not fully convinced, but that it\'s my opinion and I care about them all the same.', fr: 'Je lui dis que ça ne m\'a pas entièrement convaincu(e), mais que c\'est mon avis et que je l\'aime quand même.', de: 'Ich sage ihm/ihr, dass ich nicht vollständig überzeugt bin, aber dass das meine Meinung ist und ich ihn/sie trotzdem mag.', it: 'Gli dico che non mi ha del tutto convinto, ma che è la mia opinione e che gli voglio bene lo stesso.', pt: 'Digo que não me convenceu completamente, mas que é minha opinião e que o/a amo do mesmo jeito.' }, dimension: 'H' }] },
      ],
      characters: [
        { name: { es: 'El Mentiroso Piadoso', en: 'The Compassionate Liar', fr: 'Le Menteur Bienveillant', de: 'Der Gutmütige Lügner', it: 'Il Bugiardo Pietoso', pt: 'O Mentiroso Piedoso' }, dimensions: ['B'], photo: '/characters/kind-liar.jpg', description: { es: 'Miente para proteger a quienes quiere de verdades incómodas.', en: 'Lies to protect loved ones from uncomfortable truths.', fr: 'Ment pour protéger ses proches de vérités inconfortables.', de: 'Lügt, um geliebte Menschen vor unangenehmen Wahrheiten zu schützen.', it: 'Mente per proteggere chi ama da verità scomode.', pt: 'Mente para proteger quem ama de verdades desconfortáveis.' }, philosophy: { es: 'Mentir te cuesta algo. No lo haces por conveniencia — lo haces para evitar el dolor ajeno. Cada pequeña mentira es una elección de priorizar el bienestar del otro sobre la verdad. ¿Pero es tuyo ese derecho?', en: 'Lying costs you something. You don\'t do it for convenience — you do it to spare others pain. Each small lie is a choice to prioritize someone else\'s wellbeing over the truth. But is that right yours to make?', fr: 'Mentir te coûte quelque chose. Tu ne le fais pas par commodité — tu le fais pour éviter la douleur des autres. Chaque petit mensonge est un choix de prioriser le bien-être de l\'autre sur la vérité. Mais est-ce vraiment ton droit ?', de: 'Lügen kostet dich etwas. Du tust es nicht aus Bequemlichkeit — du tust es, um anderen Schmerz zu ersparen. Jede kleine Lüge ist eine Entscheidung, das Wohlbefinden des anderen über die Wahrheit zu stellen. Aber ist das dein Recht?', it: 'Mentire ti costa qualcosa. Non lo fai per convenienza — lo fai per evitare il dolore degli altri. Ogni piccola bugia è una scelta di dare priorità al benessere altrui sulla verità. Ma è davvero un tuo diritto?', pt: 'Mentir custa algo para você. Não faz por conveniência — faz para evitar a dor alheia. Cada pequena mentira é uma escolha de priorizar o bem-estar do outro sobre a verdade. Mas esse direito é seu?' } },
        { name: { es: 'El Mentiroso de Conveniencia', en: 'The Convenient Liar', fr: 'Le Menteur par Commodité', de: 'Der Zweckmäßige Lügner', it: 'Il Bugiardo per Convenienza', pt: 'O Mentiroso por Conveniência' }, dimensions: ['A'], photo: '/characters/convenient-liar.jpg', description: { es: 'Miente para evitar consecuencias incómodas para sí mismo.', en: 'Lies to avoid uncomfortable consequences for themselves.', fr: 'Ment pour éviter des conséquences inconfortables pour lui-même.', de: 'Lügt, um unangenehme Konsequenzen für sich selbst zu vermeiden.', it: 'Mente per evitare conseguenze scomode per sé stesso.', pt: 'Mente para evitar consequências desconfortáveis para si mesmo.' }, philosophy: { es: 'Tus mentiras siempre empiezan con la misma frase interior: "es más fácil así". Proteges tu imagen, tus posiciones, tu comodidad. No eres especialmente malicioso/a — eres humano/a, priorizando el camino de menor resistencia.', en: 'Your lies always start with the same inner phrase: "it\'s easier this way". You protect your image, your positions, your comfort. You\'re not especially malicious — you\'re human, prioritizing the path of least resistance.', fr: 'Tes mensonges commencent toujours par la même phrase intérieure : "c\'est plus facile ainsi". Tu protèges ton image, tes positions, ton confort. Tu n\'es pas particulièrement malveillant(e) — tu es humain(e), privilégiant le chemin de moindre résistance.', de: 'Deine Lügen beginnen immer mit demselben inneren Satz: "So ist es einfacher". Du schützt dein Image, deine Positionen, deinen Komfort. Du bist nicht besonders bösartig — du bist menschlich und bevorzugst den Weg des geringsten Widerstands.', it: 'Le tue bugie iniziano sempre con la stessa frase interiore: "è più facile così". Proteggi la tua immagine, le tue posizioni, il tuo comfort. Non sei particolarmente malvagio/a — sei umano/a, che dà priorità al percorso di minor resistenza.', pt: 'Suas mentiras sempre começam com a mesma frase interior: "é mais fácil assim". Você protege sua imagem, suas posições, seu conforto. Não é especialmente malicioso/a — é humano/a, priorizando o caminho de menor resistência.' } },
        { name: { es: 'El Mentiroso Social', en: 'The Social Liar', fr: 'Le Menteur Social', de: 'Der Soziale Lügner', it: 'Il Bugiardo Sociale', pt: 'O Mentiroso Social' }, dimensions: ['S'], photo: '/characters/social-liar.jpg', description: { es: 'Miente para lubricar las relaciones y evitar conflictos.', en: 'Lies to smooth relationships and avoid conflicts.', fr: 'Ment pour huiler les relations et éviter les conflits.', de: 'Lügt, um Beziehungen zu glätten und Konflikte zu vermeiden.', it: 'Mente per lubrificare le relazioni ed evitare i conflitti.', pt: 'Mente para lubrificar as relações e evitar conflitos.' }, philosophy: { es: 'Tus mentiras son el aceite de la maquinaria social. No son para ganar — son para no perder. Para mantener la armonía, para no defraudar, para que las conversaciones fluyan sin fricción.', en: 'Your lies are the oil of the social machinery. They\'re not to gain — they\'re to not lose. To maintain harmony, to not disappoint, to keep conversations flowing without friction.', fr: 'Tes mensonges sont l\'huile de la machine sociale. Ce n\'est pas pour gagner — c\'est pour ne pas perdre. Pour maintenir l\'harmonie, pour ne pas décevoir, pour que les conversations se déroulent sans friction.', de: 'Deine Lügen sind das Öl des sozialen Getriebe. Sie dienen nicht dem Gewinn — sondern dem Nichtverl ieren. Um die Harmonie zu wahren, um nicht zu enttäuschen, damit Gespräche reibungslos fließen.', it: 'Le tue bugie sono l\'olio della macchina sociale. Non servono per guadagnare — ma per non perdere. Per mantenere l\'armonia, per non deludere, per far scorrere le conversazioni senza attrito.', pt: 'Suas mentiras são o óleo da engrenagem social. Não são para ganhar — são para não perder. Para manter a harmonia, para não decepcionar, para que as conversas fluam sem atrito.' } },
        { name: { es: 'El Honesto Radical', en: 'The Radical Honest', fr: 'L\'Honnête Radical', de: 'Der Radikal Ehrliche', it: 'L\'Onesto Radicale', pt: 'O Honesto Radical' }, dimensions: ['H'], photo: '/characters/radical-honest.jpg', description: { es: 'Dice la verdad aunque cueste. A veces más de la cuenta.', en: 'Tells the truth even when it hurts. Sometimes more than necessary.', fr: 'Dit la vérité même si ça coûte. Parfois plus que nécessaire.', de: 'Sagt die Wahrheit, auch wenn es wehtut. Manchmal mehr als nötig.', it: 'Dice la verità anche se costa. A volte più del necessario.', pt: 'Diz a verdade mesmo que doa. Às vezes mais do que o necessário.' }, philosophy: { es: 'Para ti, la honestidad no es una virtud — es una necesidad. Las mentiras, incluso las piadosas, te generan una incomodidad que no puedes sostener. No siempre es popular, pero duermes con la conciencia tranquila.', en: 'For you, honesty isn\'t a virtue — it\'s a necessity. Lies, even compassionate ones, create an discomfort you can\'t sustain. It\'s not always popular, but you sleep with a clear conscience.', fr: 'Pour toi, l\'honnêteté n\'est pas une vertu — c\'est une nécessité. Les mensonges, même bienveillants, te génèrent un malaise que tu ne peux pas soutenir. Ce n\'est pas toujours populaire, mais tu dors la conscience tranquille.', de: 'Für dich ist Ehrlichkeit keine Tugend — sie ist eine Notwendigkeit. Lügen, auch gütige, erzeugen ein Unbehagen, das du nicht aufrechterhalten kannst. Es ist nicht immer beliebt, aber du schläfst mit ruhigem Gewissen.', it: 'Per te, l\'onestà non è una virtù — è una necessità. Le bugie, anche quelle pietose, ti creano un disagio che non riesci a sostenere. Non è sempre popolare, ma dormi con la coscienza tranquilla.', pt: 'Para você, a honestidade não é uma virtude — é uma necessidade. Mentiras, mesmo as piedosas, geram um desconforto que você não consegue sustentar. Nem sempre é popular, mas você dorme com a consciência tranquila.' } },
        { name: { es: 'El Diplomático', en: 'The Diplomat', fr: 'Le Diplomate', de: 'Der Diplomat', it: 'Il Diplomatico', pt: 'O Diplomata' }, dimensions: ['B', 'S'], photo: '/characters/diplomat.jpg', description: { es: 'Mezcla verdad con omisiones para navegar situaciones sociales sin herir.', en: 'Mixes truth with omissions to navigate social situations without hurting anyone.', fr: 'Mélange vérité et omissions pour naviguer dans les situations sociales sans blesser.', de: 'Mischt Wahrheit mit Auslassungen, um soziale Situationen ohne Verletzungen zu meistern.', it: 'Mescola verità con omissioni per navigare le situazioni sociali senza ferire nessuno.', pt: 'Mistura verdade com omissões para navegar situações sociais sem magoar ninguém.' }, philosophy: { es: 'Eres maestro/a del arte de decir lo necesario. No mientes exactamente — seleccionas. Dices la verdad en dosis que la situación puede tolerar. Es un arte que pocos dominan y que casi todos necesitan.', en: 'You are a master of the art of saying what\'s necessary. You don\'t exactly lie — you select. You tell the truth in doses the situation can tolerate. It\'s an art few master and almost everyone needs.', fr: 'Tu es maître(sse) de l\'art de dire ce qui est nécessaire. Tu ne mens pas exactement — tu sélectionnes. Tu dis la vérité en doses que la situation peut tolérer. C\'est un art que peu maîtrisent et dont presque tout le monde a besoin.', de: 'Du bist Meister der Kunst, das Notwendige zu sagen. Du lügst nicht genau — du wählst aus. Du sagst die Wahrheit in Dosen, die die Situation vertragen kann. Das ist eine Kunst, die wenige beherrschen und fast alle brauchen.', it: 'Sei un maestro dell\'arte di dire il necessario. Non menti esattamente — selezioni. Dici la verità in dosi che la situazione può tollerare. È un\'arte che pochi padroneggiano e di cui quasi tutti hanno bisogno.', pt: 'Você é mestre/a da arte de dizer o necessário. Não mente exatamente — seleciona. Diz a verdade em doses que a situação consegue tolerar. É uma arte que poucos dominam e de que quase todos precisam.' } },
        { name: { es: 'El Superviviente', en: 'The Survivor', fr: 'Le Survivant', de: 'Der Überlebende', it: 'Il Sopravvissuto', pt: 'O Sobrevivente' }, dimensions: ['A', 'S'], photo: '/characters/survivor.jpg', description: { es: 'Miente para protegerse y para encajar. Siempre calculando.', en: 'Lies to protect themselves and fit in. Always calculating.', fr: 'Ment pour se protéger et s\'intégrer. Toujours en train de calculer.', de: 'Lügt, um sich zu schützen und sich einzufügen. Immer kalkulierend.', it: 'Mente per proteggersi e per integrarsi. Sempre a calcolare.', pt: 'Mente para se proteger e se encaixar. Sempre calculando.' }, philosophy: { es: 'Aprendiste temprano que la verdad tiene costos que no siempre puedes pagar. Tu mentira no es crueldad — es adaptación. Has construido un sistema eficiente para navegar un mundo que no siempre es seguro para la honestidad.', en: 'You learned early that truth has costs you can\'t always afford. Your lie isn\'t cruelty — it\'s adaptation. You\'ve built an efficient system for navigating a world that isn\'t always safe for honesty.', fr: 'Tu as appris tôt que la vérité a des coûts que tu ne peux pas toujours payer. Ton mensonge n\'est pas de la cruauté — c\'est de l\'adaptation. Tu as construit un système efficace pour naviguer dans un monde qui n\'est pas toujours sûr pour l\'honnêteté.', de: 'Du hast früh gelernt, dass die Wahrheit Kosten hat, die du nicht immer tragen kannst. Deine Lüge ist keine Grausamkeit — sie ist Anpassung. Du hast ein effizientes System aufgebaut, um in einer Welt zu navigieren, die für Ehrlichkeit nicht immer sicher ist.', it: 'Hai imparato presto che la verità ha costi che non puoi sempre permetterti. La tua bugia non è crudeltà — è adattamento. Hai costruito un sistema efficiente per navigare in un mondo che non è sempre sicuro per l\'onestà.', pt: 'Você aprendeu cedo que a verdade tem custos que nem sempre pode pagar. Sua mentira não é crueldade — é adaptação. Você construiu um sistema eficiente para navegar em um mundo que nem sempre é seguro para a honestidade.' } },
        { name: { es: 'El Empático Honesto', en: 'The Empathic Honest', fr: 'L\'Honnête Empathique', de: 'Der Empathisch Ehrliche', it: 'L\'Empatico Onesto', pt: 'O Empático Honesto' }, dimensions: ['B', 'H'], photo: '/characters/empathic-honest.jpg', description: { es: 'Quiere ser honesto pero siente el peso de las palabras en los demás.', en: 'Wants to be honest but feels the weight of words on others.', fr: 'Veut être honnête mais ressent le poids des mots sur les autres.', de: 'Möchte ehrlich sein, spürt aber das Gewicht der Worte auf anderen.', it: 'Vuole essere onesto ma sente il peso delle parole sugli altri.', pt: 'Quer ser honesto mas sente o peso das palavras nos outros.' }, philosophy: { es: 'Cada verdad incómoda te cuesta decirla porque la sientes en el cuerpo del otro. Pero has aprendido que la honestidad compasiva es posible — verdad y cuidado no son opuestos.', en: 'Every uncomfortable truth costs you to say because you feel it in the other person\'s body. But you\'ve learned that compassionate honesty is possible — truth and care are not opposites.', fr: 'Chaque vérité inconfortable te coûte à dire parce que tu la ressens dans le corps de l\'autre. Mais tu as appris que l\'honnêteté compatissante est possible — vérité et soin ne sont pas opposés.', de: 'Jede unangenehme Wahrheit kostet dich etwas zu sagen, weil du sie im Körper des anderen spürst. Aber du hast gelernt, dass mitfühlende Ehrlichkeit möglich ist — Wahrheit und Fürsorge sind keine Gegensätze.', it: 'Ogni verità scomoda ti costa dirla perché la senti nel corpo dell\'altro. Ma hai imparato che l\'onestà compassionevole è possibile — verità e cura non sono opposti.', pt: 'Cada verdade desconfortável te custa dizer porque a sente no corpo do outro. Mas você aprendeu que a honestidade compassiva é possível — verdade e cuidado não são opostos.' } },
        { name: { es: 'El Transparente Social', en: 'The Social Transparent', fr: 'Le Transparent Social', de: 'Der Sozial Transparente', it: 'Il Trasparente Sociale', pt: 'O Transparente Social' }, dimensions: ['H', 'S'], photo: '/characters/transparent-social.jpg', description: { es: 'Honesto/a en esencia pero con tacto social para decir las cosas.', en: 'Honest at heart but with social tact in how they say things.', fr: 'Honnête dans l\'essence mais avec du tact social pour dire les choses.', de: 'Im Kern ehrlich, aber mit sozialem Takt beim Aussprechen.', it: 'Onesto/a nell\'essenza ma con tatto sociale nel modo di dire le cose.', pt: 'Honesto/a na essência mas com tato social para dizer as coisas.' }, philosophy: { es: 'No mientes, pero tampoco eres un martillo. Sabes cómo decir verdades difíciles de una manera que el otro pueda escuchar. Eso es más difícil que ser simplemente honesto — requiere inteligencia emocional.', en: 'You don\'t lie, but you\'re not a hammer either. You know how to deliver difficult truths in a way the other person can hear. That\'s harder than simply being honest — it requires emotional intelligence.', fr: 'Tu ne mens pas, mais tu n\'es pas non plus un marteau. Tu sais comment dire des vérités difficiles d\'une manière que l\'autre peut entendre. C\'est plus difficile que d\'être simplement honnête — cela demande de l\'intelligence émotionnelle.', de: 'Du lügst nicht, aber du bist auch kein Hammer. Du weißt, wie man schwierige Wahrheiten auf eine Weise sagt, die der andere hören kann. Das ist schwieriger als einfach ehrlich zu sein — es erfordert emotionale Intelligenz.', it: 'Non menti, ma non sei nemmeno un martello. Sai come dire verità difficili in un modo che l\'altro possa ascoltare. È più difficile che essere semplicemente onesto — richiede intelligenza emotiva.', pt: 'Você não mente, mas também não é um martelo. Sabe como dizer verdades difíceis de um jeito que o outro possa ouvir. Isso é mais difícil do que simplesmente ser honesto — requer inteligência emocional.' } },
      ],
    },
    create: {
      slug: 'liar',
      title: { es: '¿Qué tipo de mentiroso/a eres?', en: 'What type of liar are you?', fr: 'Quel type de menteur/menteuse êtes-vous ?', de: 'Was für ein Lügner bist du?', it: 'Che tipo di bugiardo/a sei?', pt: 'Que tipo de mentiroso/a você é?' },
      description: { es: 'Todos mentimos. La pregunta es: ¿por qué lo haces, con qué frecuencia y qué tan bien te va?', en: 'Everyone lies. The question is: why do you do it, how often, and how well does it serve you?', fr: 'Tout le monde ment. La question est : pourquoi le fais-tu, à quelle fréquence et dans quelle mesure ça te réussit ?', de: 'Alle lügen. Die Frage ist: Warum tust du es, wie oft und wie gut geht es dir dabei?', it: 'Tutti mentono. La domanda è: perché lo fai, con quale frequenza e quanto ti riesce bene?', pt: 'Todo mundo mente. A questão é: por que você faz isso, com que frequência e o quão bem isso funciona para você?' },
      scenarioLabel: { es: 'Situación', en: 'Situation', fr: 'Situation', de: 'Situation', it: 'Situazione', pt: 'Situação' },
      categoryId: catMap['dark-personality'],
      sortOrder: 5,
      dimensionLabels: {
        es: { B: 'Benevolencia', A: 'Autoprotección', S: 'Social', H: 'Honestidad' },
        en: { B: 'Benevolence', A: 'Self-protection', S: 'Social', H: 'Honesty' },
        fr: { B: 'Bienveillance', A: 'Auto-protection', S: 'Social', H: 'Honnêteté' },
        de: { B: 'Wohlwollen', A: 'Selbstschutz', S: 'Sozial', H: 'Ehrlichkeit' },
        it: { B: 'Benevolenza', A: 'Autoprotezzione', S: 'Sociale', H: 'Onestà' },
        pt: { B: 'Benevolência', A: 'Autoproteção', S: 'Social', H: 'Honestidade' },
      },
      questions: [
        { id: 1, situation: { es: 'Tu mejor amigo estrena una nueva canción que compuso. Es terrible. Te pregunta qué te parece.', en: 'Your best friend releases a new song they wrote. It\'s terrible. They ask what you think.', fr: 'Ton meilleur ami sort une nouvelle chanson qu\'il a composée. Elle est terrible. Il te demande ce que tu en penses.', de: 'Dein bester Freund veröffentlicht ein neues Lied, das er komponiert hat. Es ist schrecklich. Er fragt dich, was du davon hältst.', it: 'Il tuo migliore amico pubblica una nuova canzone che ha composto. È terribile. Ti chiede cosa ne pensi.', pt: 'Seu melhor amigo lança uma nova música que compôs. É horrível. Ele te pergunta o que você acha.' }, options: [{ text: { es: 'Le digo que es increíble. No voy a destruir su ilusión.', en: 'I tell them it\'s incredible. I\'m not going to crush their dream.', fr: 'Je lui dis que c\'est incroyable. Je ne vais pas briser son illusion.', de: 'Ich sage ihm, dass es großartig ist. Ich werde seine Illusion nicht zerstören.', it: 'Gli dico che è incredibile. Non voglio distruggere la sua illusione.', pt: 'Digo que é incrível. Não vou destruir a ilusão dele.' }, dimension: 'B' }, { text: { es: 'Le digo que está buena para no tener que justificar por qué no me gusta.', en: 'I say it\'s good so I don\'t have to explain why I don\'t like it.', fr: 'Je dis qu\'elle est bien pour ne pas avoir à expliquer pourquoi elle ne me plaît pas.', de: 'Ich sage, es ist gut, damit ich nicht erklären muss, warum es mir nicht gefällt.', it: 'Dico che è buona per non dover spiegare perché non mi piace.', pt: 'Digo que está boa para não ter que justificar por que não gostei.' }, dimension: 'A' }, { text: { es: 'Digo algo vago como "tiene mucha energía" y cambio el tema.', en: 'I say something vague like "it has a lot of energy" and change the subject.', fr: 'Je dis quelque chose de vague comme "elle a beaucoup d\'énergie" et je change de sujet.', de: 'Ich sage etwas Vages wie "es hat viel Energie" und wechsle das Thema.', it: 'Dico qualcosa di vago come "ha molta energia" e cambio argomento.', pt: 'Digo algo vago como "tem muita energia" e mudo de assunto.' }, dimension: 'S' }, { text: { es: 'Le digo que no es para mí pero que celebro que haya hecho algo propio.', en: 'I tell them it\'s not my thing but I celebrate that they created something of their own.', fr: 'Je lui dis que ce n\'est pas pour moi, mais que je salue le fait qu\'il ait créé quelque chose qui lui appartient.', de: 'Ich sage ihm, dass es nicht meins ist, aber ich feiere, dass er etwas Eigenes geschaffen hat.', it: 'Gli dico che non fa per me, ma apprezzo che abbia creato qualcosa di suo.', pt: 'Digo que não é para mim, mas celebro o fato de ter criado algo próprio.' }, dimension: 'H' }] },
        { id: 2, situation: { es: 'Llegas tarde a una reunión importante. ¿Qué dices?', en: 'You arrive late to an important meeting. What do you say?', fr: 'Tu arrives en retard à une réunion importante. Qu\'est-ce que tu dis ?', de: 'Du kommst zu einem wichtigen Meeting zu spät. Was sagst du?', it: 'Arrivi in ritardo a una riunione importante. Cosa dici?', pt: 'Você chega atrasado a uma reunião importante. O que você diz?' }, options: [{ text: { es: 'Invento algo: tráfico, emergencia, lo que suene creíble.', en: 'I make something up: traffic, an emergency, whatever sounds believable.', fr: 'J\'invente quelque chose : la circulation, une urgence, ce qui paraît crédible.', de: 'Ich erfinde etwas: Verkehr, Notfall, was auch immer glaubwürdig klingt.', it: 'Invento qualcosa: traffico, emergenza, qualcosa di credibile.', pt: 'Invento algo: trânsito, emergência, o que soar mais crível.' }, dimension: 'A' }, { text: { es: 'Digo que hubo un problema sin especificar. No es una mentira, exactamente.', en: 'I say there was a problem without specifying. It\'s not exactly a lie.', fr: 'Je dis qu\'il y a eu un problème sans préciser. Ce n\'est pas vraiment un mensonge.', de: 'Ich sage, es gab ein Problem, ohne Einzelheiten zu nennen. Das ist nicht direkt eine Lüge.', it: 'Dico che c\'è stato un problema senza specificare. Non è esattamente una bugia.', pt: 'Digo que houve um problema sem especificar. Não é exatamente uma mentira.' }, dimension: 'S' }, { text: { es: 'Pido disculpas sin dar explicaciones. La verdad no cambia nada.', en: 'I apologize without giving explanations. The truth doesn\'t change anything.', fr: 'Je m\'excuse sans donner d\'explication. La vérité ne changerait rien.', de: 'Ich entschuldige mich ohne Erklärungen. Die Wahrheit ändert nichts.', it: 'Chiedo scusa senza spiegazioni. La verità non cambia nulla.', pt: 'Peço desculpas sem dar explicações. A verdade não muda nada.' }, dimension: 'H' }, { text: { es: 'Invento algo que no haga quedar mal a nadie involucrado.', en: 'I make up something that doesn\'t make anyone involved look bad.', fr: 'J\'invente quelque chose qui ne fasse pas paraître quelqu\'un de mal.', de: 'Ich erfinde etwas, das niemanden schlecht aussehen lässt.', it: 'Invento qualcosa che non metta in cattiva luce nessuno.', pt: 'Invento algo que não prejudique ninguém envolvido.' }, dimension: 'B' }] },
        { id: 3, situation: { es: 'Tu pareja pregunta si esa persona que te escribió es alguien importante. No lo es, pero fue flirteo.', en: 'Your partner asks if the person who texted you is someone important. They\'re not, but there was flirting.', fr: 'Ton/ta partenaire te demande si la personne qui t\'a écrit est quelqu\'un d\'important. Non, mais c\'était du flirt.', de: 'Dein Partner fragt, ob die Person, die dir geschrieben hat, jemand Wichtiges ist. Nein, aber es war Flirten.', it: 'Il/la tuo/a partner ti chiede se quella persona che ti ha scritto è qualcuno di importante. Non lo è, ma c\'era del flirt.', pt: 'Seu parceiro pergunta se a pessoa que te escreveu é alguém importante. Não é, mas havia flerte.' }, options: [{ text: { es: 'Digo que es un conocido del trabajo. Técnicamente no es mentira.', en: 'I say it\'s a work acquaintance. Technically not a lie.', fr: 'Je dis que c\'est une connaissance du travail. Techniquement, ce n\'est pas un mensonge.', de: 'Ich sage, es ist ein Arbeitskollege. Technisch gesehen keine Lüge.', it: 'Dico che è un conoscente del lavoro. Tecnicamente non è una bugia.', pt: 'Digo que é um conhecido do trabalho. Tecnicamente não é mentira.' }, dimension: 'S' }, { text: { es: 'Lo niego directamente. No pasó nada importante y no vale la pena el conflicto.', en: 'I deny it directly. Nothing important happened and the conflict isn\'t worth it.', fr: 'Je nie directement. Il ne s\'est rien passé d\'important et ça ne vaut pas le conflit.', de: 'Ich leugne es direkt. Es ist nichts Wichtiges passiert und der Konflikt lohnt sich nicht.', it: 'Lo nego direttamente. Non è successo niente di importante e non vale il conflitto.', pt: 'Nego diretamente. Não aconteceu nada importante e não vale o conflito.' }, dimension: 'A' }, { text: { es: 'Cuento todo. Fue sin importancia, pero prefiero no cargar con el secreto.', en: 'I tell everything. It meant nothing, but I prefer not to carry the secret.', fr: 'Je raconte tout. Ce n\'était rien, mais je préfère ne pas porter ce secret.', de: 'Ich erzähle alles. Es war nichts, aber ich trage das Geheimnis lieber nicht.', it: 'Racconto tutto. Non era niente, ma preferisco non portare il segreto.', pt: 'Conto tudo. Não teve importância, mas prefiro não carregar o segredo.' }, dimension: 'H' }, { text: { es: 'Minimizo para proteger sus sentimientos: "alguien del gym, nada relevante".', en: 'I minimize to protect their feelings: "someone from the gym, nothing relevant".', fr: 'Je minimise pour protéger ses sentiments : "quelqu\'un du gym, rien d\'important".', de: 'Ich spiele es herunter, um seine Gefühle zu schützen: "jemand aus dem Fitnessstudio, nichts Wichtiges".', it: 'Minimalizzo per proteggere i suoi sentimenti: "qualcuno della palestra, niente di rilevante".', pt: 'Minimizo para proteger seus sentimentos: "alguém da academia, nada relevante".' }, dimension: 'B' }] },
        { id: 4, situation: { es: 'Un familiar pide dinero que sabes que no va a devolver. No quieres prestarlo.', en: 'A family member asks for money you know they won\'t pay back. You don\'t want to lend it.', fr: 'Un membre de ta famille demande de l\'argent que tu sais qu\'il ne rendra pas. Tu ne veux pas le prêter.', de: 'Ein Familienmitglied bittet um Geld, von dem du weißt, dass es nicht zurückgezahlt wird. Du willst es nicht leihen.', it: 'Un familiare chiede soldi che sai che non restituirà. Non vuoi prestarli.', pt: 'Um familiar pede dinheiro que você sabe que não vai devolver. Você não quer emprestar.' }, options: [{ text: { es: 'Digo que en este momento no tengo. Es más fácil que dar una negativa real.', en: 'I say I don\'t have any right now. It\'s easier than a real refusal.', fr: 'Je dis que je n\'ai pas d\'argent en ce moment. C\'est plus facile qu\'un vrai refus.', de: 'Ich sage, ich habe gerade nichts. Es ist einfacher als eine echte Absage.', it: 'Dico che al momento non ho soldi. È più facile che un rifiuto diretto.', pt: 'Digo que no momento não tenho. É mais fácil do que uma negativa real.' }, dimension: 'A' }, { text: { es: 'Digo que lo pensaré y después no respondo más los mensajes.', en: 'I say I\'ll think about it and then stop responding to messages.', fr: 'Je dis que j\'y réfléchirai, puis je ne réponds plus aux messages.', de: 'Ich sage, ich werde darüber nachdenken, und antworte dann nicht mehr auf Nachrichten.', it: 'Dico che ci penserò e poi smetto di rispondere ai messaggi.', pt: 'Digo que vou pensar e depois paro de responder as mensagens.' }, dimension: 'S' }, { text: { es: 'Le digo que no lo voy a prestar porque sé que no me lo devolverá.', en: 'I tell them I won\'t lend it because I know they won\'t pay me back.', fr: 'Je lui dis que je ne vais pas prêter parce que je sais qu\'il ne me le rendra pas.', de: 'Ich sage ihm, dass ich es nicht leihe, weil ich weiß, dass er es nicht zurückzahlt.', it: 'Gli dico che non lo presterò perché so che non me lo restituirà.', pt: 'Digo que não vou emprestar porque sei que não vai me devolver.' }, dimension: 'H' }, { text: { es: 'Le digo que tengo mis propias deudas para no hacerlo sentir rechazado.', en: 'I tell them I have my own debts so they don\'t feel rejected.', fr: 'Je lui dis que j\'ai mes propres dettes pour ne pas lui faire sentir qu\'il est rejeté.', de: 'Ich sage ihm, dass ich eigene Schulden habe, damit er sich nicht abgelehnt fühlt.', it: 'Gli dico che ho i miei debiti per non farlo sentire rifiutato.', pt: 'Digo que tenho minhas próprias dívidas para não fazê-lo sentir rejeitado.' }, dimension: 'B' }] },
        { id: 5, situation: { es: 'Te preguntan si viste la película nueva que está de moda. No la viste y no te interesa.', en: 'Someone asks if you\'ve seen the new trendy movie. You haven\'t and you\'re not interested.', fr: 'On te demande si tu as vu le nouveau film à la mode. Tu ne l\'as pas vu et ça ne t\'intéresse pas.', de: 'Man fragt dich, ob du den neuen Trendfilm gesehen hast. Du hast ihn nicht gesehen und interessierst dich nicht dafür.', it: 'Ti chiedono se hai visto il nuovo film di tendenza. Non l\'hai visto e non ti interessa.', pt: 'Te perguntam se você viu o novo filme da moda. Você não viu e não tem interesse.' }, options: [{ text: { es: 'Digo que sí y comento algo genérico que encontré en reseñas.', en: 'I say yes and comment something generic I found in reviews.', fr: 'Je dis oui et je commente quelque chose de générique trouvé dans les critiques.', de: 'Ich sage ja und kommentiere etwas Allgemeines aus Rezensionen.', it: 'Dico di sì e commento qualcosa di generico trovato nelle recensioni.', pt: 'Digo que sim e comento algo genérico que encontrei nas críticas.' }, dimension: 'S' }, { text: { es: 'Digo que la tengo pendiente para no admitir que no me interesa nada.', en: 'I say it\'s on my list to avoid admitting I\'m not interested at all.', fr: 'Je dis qu\'elle est sur ma liste pour ne pas admettre qu\'elle ne m\'intéresse pas du tout.', de: 'Ich sage, sie steht auf meiner Liste, um nicht zuzugeben, dass sie mich gar nicht interessiert.', it: 'Dico che è nella mia lista per non ammettere che non mi interessa per niente.', pt: 'Digo que está na minha lista para não admitir que não me interessa nada.' }, dimension: 'A' }, { text: { es: 'Digo que no la vi y que no me llama la atención.', en: 'I say I haven\'t seen it and it doesn\'t appeal to me.', fr: 'Je dis que je ne l\'ai pas vue et qu\'elle ne m\'attire pas.', de: 'Ich sage, ich habe ihn nicht gesehen und er spricht mich nicht an.', it: 'Dico che non l\'ho visto e non mi attira.', pt: 'Digo que não vi e que não me chama a atenção.' }, dimension: 'H' }, { text: { es: 'Digo que la tenía pendiente pero que parece que no es para mí. Para no decepcionar.', en: 'I say it was on my list but it seems it\'s not for me. So as not to disappoint.', fr: 'Je dis qu\'elle était sur ma liste mais qu\'elle ne semble pas faite pour moi. Pour ne pas décevoir.', de: 'Ich sage, sie stand auf meiner Liste, scheint aber nichts für mich zu sein. Um nicht zu enttäuschen.', it: 'Dico che era nella mia lista ma che sembra non faccia per me. Per non deludere.', pt: 'Digo que estava na minha lista, mas que parece não ser para mim. Para não decepcionar.' }, dimension: 'B' }] },
        { id: 6, situation: { es: 'Tu jefe pregunta si terminaste un proyecto que en realidad tiene otro día de trabajo pendiente.', en: 'Your boss asks if you finished a project that actually has another day of work left.', fr: 'Ton patron te demande si tu as terminé un projet qui a en réalité encore une journée de travail devant lui.', de: 'Dein Chef fragt, ob du ein Projekt abgeschlossen hast, das eigentlich noch einen weiteren Arbeitstag braucht.', it: 'Il tuo capo ti chiede se hai terminato un progetto che in realtà ha ancora un giorno di lavoro da fare.', pt: 'Seu chefe pergunta se você terminou um projeto que na verdade ainda tem um dia de trabalho pendente.' }, options: [{ text: { es: 'Digo que está casi listo y trabajo toda la noche para que así sea.', en: 'I say it\'s almost done and work through the night to make it so.', fr: 'Je dis qu\'il est presque prêt et je travaille toute la nuit pour que ça le soit.', de: 'Ich sage, es ist fast fertig, und arbeite die ganze Nacht daran.', it: 'Dico che è quasi pronto e lavoro tutta la notte per farlo diventare così.', pt: 'Digo que está quase pronto e trabalho a noite toda para que seja assim.' }, dimension: 'A' }, { text: { es: 'Digo que sí y confío en terminarlo antes de que lo revise.', en: 'I say yes and trust I\'ll finish it before they review it.', fr: 'Je dis oui et je fais confiance à ma capacité de terminer avant qu\'il le vérifie.', de: 'Ich sage ja und vertraue darauf, es fertig zu stellen, bevor er es prüft.', it: 'Dico di sì e confido di finirlo prima che lo revisioni.', pt: 'Digo que sim e confio em terminá-lo antes que ele o revise.' }, dimension: 'S' }, { text: { es: 'Le digo que me falta un día y propongo un nuevo plazo.', en: 'I tell them I need one more day and propose a new deadline.', fr: 'Je lui dis qu\'il me manque une journée et je propose un nouveau délai.', de: 'Ich sage ihm, dass mir ein Tag fehlt, und schlage eine neue Frist vor.', it: 'Gli dico che mi manca un giorno e propongo una nuova scadenza.', pt: 'Digo que falta um dia e proponho um novo prazo.' }, dimension: 'H' }, { text: { es: 'Digo que hay algunos ajustes finales para suavizar la realidad.', en: 'I say there are some final adjustments to soften the reality.', fr: 'Je dis qu\'il y a quelques ajustements finaux pour adoucir la réalité.', de: 'Ich sage, es gibt noch ein paar letzte Anpassungen, um die Realität zu mildern.', it: 'Dico che ci sono alcuni aggiustamenti finali per ammorbidire la realtà.', pt: 'Digo que há alguns ajustes finais para suavizar a realidade.' }, dimension: 'B' }] },
        { id: 7, situation: { es: 'Tu grupo de amigos quiere hacer un plan que no te apetece nada. Te preguntan si vas.', en: 'Your friend group wants to do something you have no interest in. They ask if you\'re going.', fr: 'Ton groupe d\'amis veut faire un plan qui ne te dit rien. Ils te demandent si tu viens.', de: 'Deine Freundesgruppe möchte etwas machen, das dich gar nicht anspricht. Sie fragen, ob du kommst.', it: 'Il tuo gruppo di amici vuole fare qualcosa che non ti va per niente. Ti chiedono se ci sei.', pt: 'Seu grupo de amigos quer fazer um programa que não te agrada nada. Te perguntam se você vai.' }, options: [{ text: { es: 'Invento un compromiso previo. Así no ofendo a nadie.', en: 'I make up a prior commitment. That way I don\'t offend anyone.', fr: 'J\'invente un engagement antérieur. Comme ça, je n\'offense personne.', de: 'Ich erfinde eine frühere Verpflichtung. So beleidigige ich niemanden.', it: 'Invento un impegno precedente. Così non offendo nessuno.', pt: 'Invento um compromisso anterior. Assim não ofendo ninguém.' }, dimension: 'B' }, { text: { es: 'Digo que "quizás" y luego cancelo a último momento con cualquier excusa.', en: 'I say "maybe" and then cancel at the last minute with any excuse.', fr: 'Je dis "peut-être" et j\'annule à la dernière minute avec n\'importe quelle excuse.', de: 'Ich sage "vielleicht" und sage dann in letzter Minute mit irgendeiner Ausrede ab.', it: 'Dico "forse" e poi cancello all\'ultimo momento con qualsiasi scusa.', pt: 'Digo que "talvez" e depois cancelo de última hora com qualquer desculpa.' }, dimension: 'A' }, { text: { es: 'Digo que lo veo complicado sin dar detalles.', en: 'I say it\'s complicated without giving details.', fr: 'Je dis que ça semble compliqué sans donner de détails.', de: 'Ich sage, es ist kompliziert, ohne Details zu nennen.', it: 'Dico che lo vedo complicato senza dare dettagli.', pt: 'Digo que vejo complicado sem dar detalhes.' }, dimension: 'S' }, { text: { es: 'Digo que no es para mí ese tipo de plan y propongo algo diferente.', en: 'I say that type of plan isn\'t for me and suggest something different.', fr: 'Je dis que ce type de plan n\'est pas pour moi et je propose quelque chose de différent.', de: 'Ich sage, diese Art von Plan ist nichts für mich, und schlage etwas anderes vor.', it: 'Dico che quel tipo di piano non fa per me e propongo qualcosa di diverso.', pt: 'Digo que esse tipo de programa não é para mim e proponho algo diferente.' }, dimension: 'H' }] },
        { id: 8, situation: { es: 'Rompes algo valioso de tu pareja por accidente. Nadie lo vio.', en: 'You accidentally break something valuable belonging to your partner. Nobody saw it.', fr: 'Tu casses accidentellement quelque chose de précieux appartenant à ton/ta partenaire. Personne ne l\'a vu.', de: 'Du zerbrichst versehentlich etwas Wertvolles von deinem Partner. Niemand hat es gesehen.', it: 'Rompi accidentalmente qualcosa di prezioso del tuo/a partner. Nessuno ha visto.', pt: 'Você quebra acidentalmente algo valioso do seu parceiro. Ninguém viu.' }, options: [{ text: { es: 'Lo escondo y cuando lo descubran, digo que no sé qué pasó.', en: 'I hide it and when they discover it, I say I don\'t know what happened.', fr: 'Je le cache et quand on le découvre, je dis que je ne sais pas ce qui s\'est passé.', de: 'Ich verstecke es, und wenn es entdeckt wird, sage ich, dass ich nicht weiß, was passiert ist.', it: 'Lo nascondo e quando lo scoprono, dico che non so cosa è successo.', pt: 'Escondo e quando descobrirem, digo que não sei o que aconteceu.' }, dimension: 'A' }, { text: { es: 'Digo que lo encontré así. Quizás ya estaba roto antes.', en: 'I say I found it like that. Maybe it was already broken.', fr: 'Je dis que je l\'ai trouvé comme ça. Peut-être qu\'il était déjà cassé avant.', de: 'Ich sage, ich habe es so gefunden. Vielleicht war es schon vorher kaputt.', it: 'Dico che l\'ho trovato così. Forse era già rotto prima.', pt: 'Digo que encontrei assim. Talvez já estivesse quebrado antes.' }, dimension: 'S' }, { text: { es: 'Lo cuento inmediatamente. Los accidentes pasan y ocultarlo sería peor.', en: 'I tell them immediately. Accidents happen and hiding it would be worse.', fr: 'Je le dis immédiatement. Les accidents arrivent et le cacher serait pire.', de: 'Ich sage es sofort. Unfälle passieren und es zu verbergen wäre schlimmer.', it: 'Lo dico immediatamente. Gli incidenti capitano e nasconderlo sarebbe peggio.', pt: 'Conto imediatamente. Acidentes acontecem e esconder seria pior.' }, dimension: 'H' }, { text: { es: 'Lo reemplazo en secreto antes de que se dé cuenta. Sin necesidad de conversaciones difíciles.', en: 'I replace it secretly before they notice. No need for difficult conversations.', fr: 'Je le remplace secrètement avant qu\'ils s\'en aperçoivent. Sans avoir besoin de conversations difficiles.', de: 'Ich ersetze es heimlich, bevor sie es bemerken. Ohne schwierige Gespräche.', it: 'Lo sostituisco in segreto prima che se ne accorga. Senza bisogno di conversazioni difficili.', pt: 'Substituo em segredo antes que perceba. Sem necessidade de conversas difíceis.' }, dimension: 'B' }] },
        { id: 9, situation: { es: 'Alguien te pregunta cuánto ganaste en tu último trabajo. Es una pregunta incómoda.', en: 'Someone asks how much you earned at your last job. It\'s an uncomfortable question.', fr: 'Quelqu\'un te demande combien tu gagnais dans ton dernier travail. C\'est une question inconfortable.', de: 'Jemand fragt dich, wie viel du in deinem letzten Job verdient hast. Eine unangenehme Frage.', it: 'Qualcuno ti chiede quanto guadagnavi nel tuo ultimo lavoro. È una domanda scomoda.', pt: 'Alguém te pergunta quanto você ganhou no seu último emprego. É uma pergunta desconfortável.' }, options: [{ text: { es: 'Doy una cifra 20% más alta. Es una negociación, no una confesión.', en: 'I give a number 20% higher. It\'s a negotiation, not a confession.', fr: 'Je donne un chiffre 20 % plus élevé. C\'est une négociation, pas une confession.', de: 'Ich nenne eine Zahl, die 20 % höher ist. Das ist eine Verhandlung, kein Geständnis.', it: 'Do una cifra del 20% più alta. È una trattativa, non una confessione.', pt: 'Dou um número 20% maior. É uma negociação, não uma confissão.' }, dimension: 'A' }, { text: { es: 'Doy una cifra aproximada que suene bien sin ser exacta.', en: 'I give an approximate number that sounds good without being exact.', fr: 'Je donne un chiffre approximatif qui sonne bien sans être exact.', de: 'Ich nenne eine ungefähre Zahl, die gut klingt, ohne genau zu sein.', it: 'Do una cifra approssimativa che suoni bene senza essere esatta.', pt: 'Dou um número aproximado que soe bem sem ser exato.' }, dimension: 'S' }, { text: { es: 'Digo la cifra real. No tengo nada que esconder.', en: 'I say the real number. I have nothing to hide.', fr: 'Je donne le vrai chiffre. Je n\'ai rien à cacher.', de: 'Ich sage die echte Zahl. Ich habe nichts zu verbergen.', it: 'Dico la cifra reale. Non ho nulla da nascondere.', pt: 'Digo o número real. Não tenho nada a esconder.' }, dimension: 'H' }, { text: { es: 'Evado la pregunta con un "depende del contexto" para no incomodar.', en: 'I dodge the question with a "it depends on context" so as not to make anyone uncomfortable.', fr: 'J\'esquive la question avec un "ça dépend du contexte" pour ne pas mettre mal à l\'aise.', de: 'Ich weiche der Frage mit einem "es kommt auf den Kontext an" aus, um niemanden in Verlegenheit zu bringen.', it: 'Evito la domanda con un "dipende dal contesto" per non mettere a disagio.', pt: 'Esquivo da pergunta com um "depende do contexto" para não constranger.' }, dimension: 'B' }] },
        { id: 10, situation: { es: 'Tu amigo/a te pregunta qué piensas de su nueva pareja. No te cae bien.', en: 'Your friend asks what you think of their new partner. You don\'t like them.', fr: 'Ton/ta ami(e) te demande ce que tu penses de son/sa nouveau/nouvelle partenaire. Tu ne l\'aimes pas.', de: 'Dein Freund/deine Freundin fragt dich, was du von seinem/ihrem neuen Partner hältst. Du magst ihn/sie nicht.', it: 'Il/la tuo/a amico/a ti chiede cosa pensi del/della suo/a nuovo/a partner. Non ti piace.', pt: 'Seu amigo/a te pergunta o que você acha do novo parceiro/a. Você não gosta.' }, options: [{ text: { es: 'Le digo que parece muy buena persona aunque no me haya parecido tal cosa.', en: 'I tell them they seem like a great person even though I don\'t think so.', fr: 'Je lui dis que ça a l\'air d\'être une très bonne personne même si ce n\'est pas mon avis.', de: 'Ich sage, er/sie wirkt wie eine tolle Person, obwohl ich das nicht finde.', it: 'Gli dico che sembra una persona molto buona anche se non la penso così.', pt: 'Digo que parece uma ótima pessoa mesmo não pensando isso.' }, dimension: 'B' }, { text: { es: 'Digo que es pronto para opinar y que lo que importa es que mi amigo/a sea feliz.', en: 'I say it\'s too early to give an opinion and that what matters is my friend\'s happiness.', fr: 'Je dis qu\'il est trop tôt pour donner mon avis et que ce qui compte c\'est que mon ami(e) soit heureux/heureuse.', de: 'Ich sage, es ist zu früh für eine Meinung und was zählt ist, dass mein Freund/meine Freundin glücklich ist.', it: 'Dico che è presto per esprimere un opinione e che ciò che conta è che il/la mio/a amico/a sia felice.', pt: 'Digo que é cedo para opinar e que o que importa é que meu/minha amigo/a seja feliz.' }, dimension: 'S' }, { text: { es: 'Guardo mis opiniones. No me lo preguntaron para que destruya algo que lo hace feliz.', en: 'I keep my opinions to myself. They didn\'t ask me to destroy something that makes them happy.', fr: 'Je garde mes opinions pour moi. On ne m\'a pas demandé de détruire quelque chose qui rend mon ami(e) heureux/heureuse.', de: 'Ich behalte meine Meinung für mich. Man hat mich nicht gefragt, um etwas zu zerstören, das ihn/sie glücklich macht.', it: 'Tengo le mie opinioni per me. Non mi è stato chiesto di distruggere qualcosa che lo rende felice.', pt: 'Guardo minhas opiniões. Não me pediram para destruir algo que o faz feliz.' }, dimension: 'A' }, { text: { es: 'Le digo que no me terminó de convencer pero que es mi opinión y que lo quiero igual.', en: 'I tell them I\'m not fully convinced, but that it\'s my opinion and I care about them all the same.', fr: 'Je lui dis que ça ne m\'a pas entièrement convaincu(e), mais que c\'est mon avis et que je l\'aime quand même.', de: 'Ich sage ihm/ihr, dass ich nicht vollständig überzeugt bin, aber dass das meine Meinung ist und ich ihn/sie trotzdem mag.', it: 'Gli dico che non mi ha del tutto convinto, ma che è la mia opinione e che gli voglio bene lo stesso.', pt: 'Digo que não me convenceu completamente, mas que é minha opinião e que o/a amo do mesmo jeito.' }, dimension: 'H' }] },
      ],
      characters: [
        { name: { es: 'El Mentiroso Piadoso', en: 'The Compassionate Liar', fr: 'Le Menteur Bienveillant', de: 'Der Gutmütige Lügner', it: 'Il Bugiardo Pietoso', pt: 'O Mentiroso Piedoso' }, dimensions: ['B'], photo: '/characters/kind-liar.jpg', description: { es: 'Miente para proteger a quienes quiere de verdades incómodas.', en: 'Lies to protect loved ones from uncomfortable truths.', fr: 'Ment pour protéger ses proches de vérités inconfortables.', de: 'Lügt, um geliebte Menschen vor unangenehmen Wahrheiten zu schützen.', it: 'Mente per proteggere chi ama da verità scomode.', pt: 'Mente para proteger quem ama de verdades desconfortáveis.' }, philosophy: { es: 'Mentir te cuesta algo. No lo haces por conveniencia — lo haces para evitar el dolor ajeno. Cada pequeña mentira es una elección de priorizar el bienestar del otro sobre la verdad. ¿Pero es tuyo ese derecho?', en: 'Lying costs you something. You don\'t do it for convenience — you do it to spare others pain. Each small lie is a choice to prioritize someone else\'s wellbeing over the truth. But is that right yours to make?', fr: 'Mentir te coûte quelque chose. Tu ne le fais pas par commodité — tu le fais pour éviter la douleur des autres. Chaque petit mensonge est un choix de prioriser le bien-être de l\'autre sur la vérité. Mais est-ce vraiment ton droit ?', de: 'Lügen kostet dich etwas. Du tust es nicht aus Bequemlichkeit — du tust es, um anderen Schmerz zu ersparen. Jede kleine Lüge ist eine Entscheidung, das Wohlbefinden des anderen über die Wahrheit zu stellen. Aber ist das dein Recht?', it: 'Mentire ti costa qualcosa. Non lo fai per convenienza — lo fai per evitare il dolore degli altri. Ogni piccola bugia è una scelta di dare priorità al benessere altrui sulla verità. Ma è davvero un tuo diritto?', pt: 'Mentir custa algo para você. Não faz por conveniência — faz para evitar a dor alheia. Cada pequena mentira é uma escolha de priorizar o bem-estar do outro sobre a verdade. Mas esse direito é seu?' } },
        { name: { es: 'El Mentiroso de Conveniencia', en: 'The Convenient Liar', fr: 'Le Menteur par Commodité', de: 'Der Zweckmäßige Lügner', it: 'Il Bugiardo per Convenienza', pt: 'O Mentiroso por Conveniência' }, dimensions: ['A'], photo: '/characters/convenient-liar.jpg', description: { es: 'Miente para evitar consecuencias incómodas para sí mismo.', en: 'Lies to avoid uncomfortable consequences for themselves.', fr: 'Ment pour éviter des conséquences inconfortables pour lui-même.', de: 'Lügt, um unangenehme Konsequenzen für sich selbst zu vermeiden.', it: 'Mente per evitare conseguenze scomode per sé stesso.', pt: 'Mente para evitar consequências desconfortáveis para si mesmo.' }, philosophy: { es: 'Tus mentiras siempre empiezan con la misma frase interior: "es más fácil así". Proteges tu imagen, tus posiciones, tu comodidad. No eres especialmente malicioso/a — eres humano/a, priorizando el camino de menor resistencia.', en: 'Your lies always start with the same inner phrase: "it\'s easier this way". You protect your image, your positions, your comfort. You\'re not especially malicious — you\'re human, prioritizing the path of least resistance.', fr: 'Tes mensonges commencent toujours par la même phrase intérieure : "c\'est plus facile ainsi". Tu protèges ton image, tes positions, ton confort. Tu n\'es pas particulièrement malveillant(e) — tu es humain(e), privilégiant le chemin de moindre résistance.', de: 'Deine Lügen beginnen immer mit demselben inneren Satz: "So ist es einfacher". Du schützt dein Image, deine Positionen, deinen Komfort. Du bist nicht besonders bösartig — du bist menschlich und bevorzugst den Weg des geringsten Widerstands.', it: 'Le tue bugie iniziano sempre con la stessa frase interiore: "è più facile così". Proteggi la tua immagine, le tue posizioni, il tuo comfort. Non sei particolarmente malvagio/a — sei umano/a, che dà priorità al percorso di minor resistenza.', pt: 'Suas mentiras sempre começam com a mesma frase interior: "é mais fácil assim". Você protege sua imagem, suas posições, seu conforto. Não é especialmente malicioso/a — é humano/a, priorizando o caminho de menor resistência.' } },
        { name: { es: 'El Mentiroso Social', en: 'The Social Liar', fr: 'Le Menteur Social', de: 'Der Soziale Lügner', it: 'Il Bugiardo Sociale', pt: 'O Mentiroso Social' }, dimensions: ['S'], photo: '/characters/social-liar.jpg', description: { es: 'Miente para lubricar las relaciones y evitar conflictos.', en: 'Lies to smooth relationships and avoid conflicts.', fr: 'Ment pour huiler les relations et éviter les conflits.', de: 'Lügt, um Beziehungen zu glätten und Konflikte zu vermeiden.', it: 'Mente per lubrificare le relazioni ed evitare i conflitti.', pt: 'Mente para lubrificar as relações e evitar conflitos.' }, philosophy: { es: 'Tus mentiras son el aceite de la maquinaria social. No son para ganar — son para no perder. Para mantener la armonía, para no defraudar, para que las conversaciones fluyan sin fricción.', en: 'Your lies are the oil of the social machinery. They\'re not to gain — they\'re to not lose. To maintain harmony, to not disappoint, to keep conversations flowing without friction.', fr: 'Tes mensonges sont l\'huile de la machine sociale. Ce n\'est pas pour gagner — c\'est pour ne pas perdre. Pour maintenir l\'harmonie, pour ne pas décevoir, pour que les conversations se déroulent sans friction.', de: 'Deine Lügen sind das Öl des sozialen Getriebes. Sie dienen nicht dem Gewinn — sondern dem Nichtverlieren. Um die Harmonie zu wahren, um nicht zu enttäuschen, damit Gespräche reibungslos fließen.', it: 'Le tue bugie sono l\'olio della macchina sociale. Non servono per guadagnare — ma per non perdere. Per mantenere l\'armonia, per non deludere, per far scorrere le conversazioni senza attrito.', pt: 'Suas mentiras são o óleo da engrenagem social. Não são para ganhar — são para não perder. Para manter a harmonia, para não decepcionar, para que as conversas fluam sem atrito.' } },
        { name: { es: 'El Honesto Radical', en: 'The Radical Honest', fr: 'L\'Honnête Radical', de: 'Der Radikal Ehrliche', it: 'L\'Onesto Radicale', pt: 'O Honesto Radical' }, dimensions: ['H'], photo: '/characters/radical-honest.jpg', description: { es: 'Dice la verdad aunque cueste. A veces más de la cuenta.', en: 'Tells the truth even when it hurts. Sometimes more than necessary.', fr: 'Dit la vérité même si ça coûte. Parfois plus que nécessaire.', de: 'Sagt die Wahrheit, auch wenn es wehtut. Manchmal mehr als nötig.', it: 'Dice la verità anche se costa. A volte più del necessario.', pt: 'Diz a verdade mesmo que doa. Às vezes mais do que o necessário.' }, philosophy: { es: 'Para ti, la honestidad no es una virtud — es una necesidad. Las mentiras, incluso las piadosas, te generan una incomodidad que no puedes sostener. No siempre es popular, pero duermes con la conciencia tranquila.', en: 'For you, honesty isn\'t a virtue — it\'s a necessity. Lies, even compassionate ones, create a discomfort you can\'t sustain. It\'s not always popular, but you sleep with a clear conscience.', fr: 'Pour toi, l\'honnêteté n\'est pas une vertu — c\'est une nécessité. Les mensonges, même bienveillants, te génèrent un malaise que tu ne peux pas soutenir. Ce n\'est pas toujours populaire, mais tu dors la conscience tranquille.', de: 'Für dich ist Ehrlichkeit keine Tugend — sie ist eine Notwendigkeit. Lügen, auch gütige, erzeugen ein Unbehagen, das du nicht aufrechterhalten kannst. Es ist nicht immer beliebt, aber du schläfst mit ruhigem Gewissen.', it: 'Per te, l\'onestà non è una virtù — è una necessità. Le bugie, anche quelle pietose, ti creano un disagio che non riesci a sostenere. Non è sempre popolare, ma dormi con la coscienza tranquilla.', pt: 'Para você, a honestidade não é uma virtude — é uma necessidade. Mentiras, mesmo as piedosas, geram um desconforto que você não consegue sustentar. Nem sempre é popular, mas você dorme com a consciência tranquila.' } },
        { name: { es: 'El Diplomático', en: 'The Diplomat', fr: 'Le Diplomate', de: 'Der Diplomat', it: 'Il Diplomatico', pt: 'O Diplomata' }, dimensions: ['B', 'S'], photo: '/characters/diplomat.jpg', description: { es: 'Mezcla verdad con omisiones para navegar situaciones sociales sin herir.', en: 'Mixes truth with omissions to navigate social situations without hurting anyone.', fr: 'Mélange vérité et omissions pour naviguer dans les situations sociales sans blesser.', de: 'Mischt Wahrheit mit Auslassungen, um soziale Situationen ohne Verletzungen zu meistern.', it: 'Mescola verità con omissioni per navigare le situazioni sociali senza ferire nessuno.', pt: 'Mistura verdade com omissões para navegar situações sociais sem magoar ninguém.' }, philosophy: { es: 'Eres maestro/a del arte de decir lo necesario. No mientes exactamente — seleccionas. Dices la verdad en dosis que la situación puede tolerar. Es un arte que pocos dominan y que casi todos necesitan.', en: 'You are a master of the art of saying what\'s necessary. You don\'t exactly lie — you select. You tell the truth in doses the situation can tolerate. It\'s an art few master and almost everyone needs.', fr: 'Tu es maître(sse) de l\'art de dire ce qui est nécessaire. Tu ne mens pas exactement — tu sélectionnes. Tu dis la vérité en doses que la situation peut tolérer. C\'est un art que peu maîtrisent et dont presque tout le monde a besoin.', de: 'Du bist Meister der Kunst, das Notwendige zu sagen. Du lügst nicht genau — du wählst aus. Du sagst die Wahrheit in Dosen, die die Situation vertragen kann. Das ist eine Kunst, die wenige beherrschen und fast alle brauchen.', it: 'Sei un maestro dell\'arte di dire il necessario. Non menti esattamente — selezioni. Dici la verità in dosi che la situazione può tollerare. È un\'arte che pochi padroneggiano e di cui quasi tutti hanno bisogno.', pt: 'Você é mestre/a da arte de dizer o necessário. Não mente exatamente — seleciona. Diz a verdade em doses que a situação consegue tolerar. É uma arte que poucos dominam e de que quase todos precisam.' } },
        { name: { es: 'El Superviviente', en: 'The Survivor', fr: 'Le Survivant', de: 'Der Überlebende', it: 'Il Sopravvissuto', pt: 'O Sobrevivente' }, dimensions: ['A', 'S'], photo: '/characters/survivor.jpg', description: { es: 'Miente para protegerse y para encajar. Siempre calculando.', en: 'Lies to protect themselves and fit in. Always calculating.', fr: 'Ment pour se protéger et s\'intégrer. Toujours en train de calculer.', de: 'Lügt, um sich zu schützen und sich einzufügen. Immer kalkulierend.', it: 'Mente per proteggersi e per integrarsi. Sempre a calcolare.', pt: 'Mente para se proteger e se encaixar. Sempre calculando.' }, philosophy: { es: 'Aprendiste temprano que la verdad tiene costos que no siempre puedes pagar. Tu mentira no es crueldad — es adaptación. Has construido un sistema eficiente para navegar un mundo que no siempre es seguro para la honestidad.', en: 'You learned early that truth has costs you can\'t always afford. Your lie isn\'t cruelty — it\'s adaptation. You\'ve built an efficient system for navigating a world that isn\'t always safe for honesty.', fr: 'Tu as appris tôt que la vérité a des coûts que tu ne peux pas toujours payer. Ton mensonge n\'est pas de la cruauté — c\'est de l\'adaptation. Tu as construit un système efficace pour naviguer dans un monde qui n\'est pas toujours sûr pour l\'honnêteté.', de: 'Du hast früh gelernt, dass die Wahrheit Kosten hat, die du nicht immer tragen kannst. Deine Lüge ist keine Grausamkeit — sie ist Anpassung. Du hast ein effizientes System aufgebaut, um in einer Welt zu navigieren, die für Ehrlichkeit nicht immer sicher ist.', it: 'Hai imparato presto che la verità ha costi che non puoi sempre permetterti. La tua bugia non è crudeltà — è adattamento. Hai costruito un sistema efficiente per navigare in un mondo che non è sempre sicuro per l\'onestà.', pt: 'Você aprendeu cedo que a verdade tem custos que nem sempre pode pagar. Sua mentira não é crueldade — é adaptação. Você construiu um sistema eficiente para navegar em um mundo que nem sempre é seguro para a honestidade.' } },
        { name: { es: 'El Empático Honesto', en: 'The Empathic Honest', fr: 'L\'Honnête Empathique', de: 'Der Empathisch Ehrliche', it: 'L\'Empatico Onesto', pt: 'O Empático Honesto' }, dimensions: ['B', 'H'], photo: '/characters/empathic-honest.jpg', description: { es: 'Quiere ser honesto pero siente el peso de las palabras en los demás.', en: 'Wants to be honest but feels the weight of words on others.', fr: 'Veut être honnête mais ressent le poids des mots sur les autres.', de: 'Möchte ehrlich sein, spürt aber das Gewicht der Worte auf anderen.', it: 'Vuole essere onesto ma sente il peso delle parole sugli altri.', pt: 'Quer ser honesto mas sente o peso das palavras nos outros.' }, philosophy: { es: 'Cada verdad incómoda te cuesta decirla porque la sientes en el cuerpo del otro. Pero has aprendido que la honestidad compasiva es posible — verdad y cuidado no son opuestos.', en: 'Every uncomfortable truth costs you to say because you feel it in the other person\'s body. But you\'ve learned that compassionate honesty is possible — truth and care are not opposites.', fr: 'Chaque vérité inconfortable te coûte à dire parce que tu la ressens dans le corps de l\'autre. Mais tu as appris que l\'honnêteté compatissante est possible — vérité et soin ne sont pas opposés.', de: 'Jede unangenehme Wahrheit kostet dich etwas zu sagen, weil du sie im Körper des anderen spürst. Aber du hast gelernt, dass mitfühlende Ehrlichkeit möglich ist — Wahrheit und Fürsorge sind keine Gegensätze.', it: 'Ogni verità scomoda ti costa dirla perché la senti nel corpo dell\'altro. Ma hai imparato che l\'onestà compassionevole è possibile — verità e cura non sono opposti.', pt: 'Cada verdade desconfortável te custa dizer porque a sente no corpo do outro. Mas você aprendeu que a honestidade compassiva é possível — verdade e cuidado não são opostos.' } },
        { name: { es: 'El Transparente Social', en: 'The Social Transparent', fr: 'Le Transparent Social', de: 'Der Sozial Transparente', it: 'Il Trasparente Sociale', pt: 'O Transparente Social' }, dimensions: ['H', 'S'], photo: '/characters/transparent-social.jpg', description: { es: 'Honesto/a en esencia pero con tacto social para decir las cosas.', en: 'Honest at heart but with social tact in how they say things.', fr: 'Honnête dans l\'essence mais avec du tact social pour dire les choses.', de: 'Im Kern ehrlich, aber mit sozialem Takt beim Aussprechen.', it: 'Onesto/a nell\'essenza ma con tatto sociale nel modo di dire le cose.', pt: 'Honesto/a na essência mas com tato social para dizer as coisas.' }, philosophy: { es: 'No mientes, pero tampoco eres un martillo. Sabes cómo decir verdades difíciles de una manera que el otro pueda escuchar. Eso es más difícil que ser simplemente honesto — requiere inteligencia emocional.', en: 'You don\'t lie, but you\'re not a hammer either. You know how to deliver difficult truths in a way the other person can hear. That\'s harder than simply being honest — it requires emotional intelligence.', fr: 'Tu ne mens pas, mais tu n\'es pas non plus un marteau. Tu sais comment dire des vérités difficiles d\'une manière que l\'autre peut entendre. C\'est plus difficile que d\'être simplement honnête — cela demande de l\'intelligence émotionnelle.', de: 'Du lügst nicht, aber du bist auch kein Hammer. Du weißt, wie man schwierige Wahrheiten auf eine Weise sagt, die der andere hören kann. Das ist schwieriger als einfach ehrlich zu sein — es erfordert emotionale Intelligenz.', it: 'Non menti, ma non sei nemmeno un martello. Sai come dire verità difficili in un modo che l\'altro possa ascoltare. È più difficile che essere semplicemente onesto — richiede intelligenza emotiva.', pt: 'Você não mente, mas também não é um martelo. Sabe como dizer verdades difíceis de um jeito que o outro possa ouvir. Isso é mais difícil do que simplesmente ser honesto — requer inteligência emocional.' } },
      ],
    },
  });
}
